  "google-immersive-product": {
    "slug": "google-immersive-product",
    "title": "Google Immersive Product API",
    "description": "With the Google Immersive Product API, you can fetch extended product information from the \"Immersive Product\" block, which displays a pop-up with complete details when clicked.",
    "category": "Google SERP",
    "method": "GET",
    "path": "/scrape/google/immersive-product",
    "cost": 5,
    "required": [
      "pageToken"
    ],
    "properties": {
      "pageToken": {
        "type": "string",
        "description": "Token for displaying more product info in the Google immersive pop-up, available in the Google Shopping API response as the `immersiveProductPageToken` property.",
        "wireName": "pageToken",
        "default": ""
      },
      "moreStores": {
        "type": "boolean",
        "description": "Fetch additional store results in a single search. By default it returns 3–5 stores, and when true it returns up to 13 or the maximum available for the product.",
        "wireName": "moreStores"
      },
      "nextPageToken": {
        "type": "string",
        "description": "Token used to retrieve the next page of store results.",
        "wireName": "nextPageToken"
      }
    }
  },
